INSERT INTO lessons (language_code, cefr_level, skill, title, title_translation, description, description_translation, content, order_index) VALUES
('de', 'A2', 'listening', 'Der Wetterbericht', 'The Weather Report', 'Hören Sie das Wetter für Deutschland.', 'Listen to the weather for Germany.', '{"type":"listen_and_choose","instructions":"Wie ist das Wetter?","exercises":[{"prompt":"Im Norden ist es heute bewölkt und es regnet leicht.","question":"Wetter im Norden?","options":["Sonnig","Regnerisch","Schnee"],"correct":1,"hint":"Listen for ''regnet''."},{"prompt":"Im Süden scheint die Sonne bei Temperaturen bis zu 25 Grad.","question":"Temperatur im Süden?","options":["15 Grad","20 Grad","25 Grad"],"correct":2,"hint":"Number check."},{"prompt":"Abends gibt es im Westen starke Gewitter.","question":"Wann gibt es Gewitter?","options":["Morgens","Mittags","Abends"],"correct":2,"hint":"Time of day."},{"prompt":"Der Wind weht schwach aus Osten.","question":"Woher kommt der Wind?","options":["Norden","Osten","Westen"],"correct":1,"hint":"Himmelsrichtung."},{"prompt":"Morgen wird es überall kühler und windig.","question":"Wetter morgen?","options":["Wärmer","Kühler"],"correct":1,"hint":"Listen for the comparative."},{"prompt":"Im Osten ist es heute windig und kühl, etwa 10 Grad.","question":"Wie ist die Temperatur im Osten?","options":["10 Grad","15 Grad","20 Grad"],"correct":0,"hint":"Höre auf die Gradzahl."},{"prompt":"Im Westen ist es sonnig mit Temperaturen um 30 Grad.","question":"Wetter im Westen?","options":["Kühl","Sonnig","Regnerisch"],"correct":1,"hint":"Achte auf das Wort ''sonnig''."},{"prompt":"Im Süden gibt es heute dichten Nebel.","question":"Was ist das Wetter im Süden?","options":["Nebelig","Sonnig","Windig"],"correct":0,"hint":"Achte auf ''Nebel''."},{"prompt":"Im Norden schneit es heute den ganzen Tag.","question":"Wetter im Norden?","options":["Schnee","Regnerisch","Sonnig"],"correct":0,"hint":"Höre auf das Wort ''schneit''."},{"prompt":"Morgens ist es im Osten kühl, aber nachmittags wird es warm.","question":"Wie ist das Wetter am Nachmittag im Osten?","options":["Kühl","Warm","Regnerisch"],"correct":1,"hint":"Denke an die Zeit nachmittags."},{"prompt":"Im Westen gibt es heute viel Sonnenschein und keine Wolken.","question":"Wie ist das Wetter im Westen?","options":["Bewölkt","Sonnig","Regnerisch"],"correct":1,"hint":"Achte auf ''keine Wolken''."},{"prompt":"In der Mitte des Landes ist es heute sehr heiß, etwa 35 Grad.","question":"Temperatur in der Mitte des Landes?","options":["25 Grad","30 Grad","35 Grad"],"correct":2,"hint":"Höre auf die Temperatur."},{"prompt":"Abends wird es im Süden stürmisch.","question":"Wann wird es stürmisch?","options":["Morgens","Mittags","Abends"],"correct":2,"hint":"Denke an die Tageszeit abends."},{"prompt":"Im Norden gibt es heute einen leichten Nieselregen.","question":"Wetter im Norden?","options":["Sonnig","Nieselregen","Schnee"],"correct":1,"hint":"Höre auf das Wort ''Nieselregen''."},{"prompt":"Im Süden ist es heute mild mit Temperaturen um 20 Grad.","question":"Wie ist die Temperatur im Süden?","options":["20 Grad","25 Grad","30 Grad"],"correct":0,"hint":"Achte auf die Gradzahl."},{"prompt":"Im Osten gibt es heute Gewitter mit Blitz und Donner.","question":"Wetter im Osten?","options":["Klar","Gewitter","Windig"],"correct":1,"hint":"Höre auf ''Gewitter''."},{"prompt":"Im Westen bleibt es heute trocken und sonnig.","question":"Wie ist das Wetter im Westen?","options":["Regnerisch","Sonnig","Schnee"],"correct":1,"hint":"Denke an ''trocken und sonnig''."},{"prompt":"Im Norden ist es neblig und die Sicht ist eingeschränkt.","question":"Was ist das Wetter im Norden?","options":["Nebelig","Sonnig","Kühl"],"correct":0,"hint":"Achte auf ''Sicht eingeschränkt''."},{"prompt":"Im Süden gibt es heute einen Wolkenbruch mit starkem Regen.","question":"Wetter im Süden?","options":["Bewölkt","Regnerisch","Sonnig"],"correct":1,"hint":"Höre auf ''Wolkenbruch''."},{"prompt":"Im Osten wird es heute unbeständig mit Schauern.","question":"Wie ist das Wetter im Osten?","options":["Sonnig","Unbeständig","Kühl"],"correct":1,"hint":"Höre auf ''unbeständig''."}]}', 11),
('de', 'A2', 'listening', 'Durchsagen am Bahnhof', 'Announcements at the Station', 'Hören Sie wichtige Reiseinformationen.', 'Listen to important travel info.', '{"type":"listen_and_choose","instructions":"Welche Information ist korrekt?","exercises":[{"prompt":"Gleis vier. Der ICE nach München fährt heute zehn Minuten später ab.","question":"Wie viel Verspätung?","options":["5 Min","10 Min","15 Min"],"correct":1,"hint":"Zehn."},{"prompt":"Vorsicht bei der Einfahrt des Zuges auf Gleis acht.","question":"Welches Gleis?","options":["7","8","9"],"correct":1,"hint":"Acht."},{"prompt":"Der Regionalexpress nach Hamburg fällt heute leider aus.","question":"Was passiert mit dem Zug?","options":["Fährt pünktlich","Fällt aus","Hat Verspätung"],"correct":1,"hint":"Fällt aus (cancelled)."},{"prompt":"Bitte halten Sie den Einstieg für ankommende Fahrgäste frei.","question":"Was soll man tun?","options":["Einsteigen","Platz machen","Warten"],"correct":1,"hint":"Freihalten."},{"prompt":"Nächster Halt: Hauptbahnhof. Umstieg zum Stadtbus möglich.","question":"Wo kann man umsteigen?","options":["U-Bahn","Stadtbus","Taxi"],"correct":1,"hint":"Hören Sie das Verkehrsmittel."},{"prompt":"Der Zug nach Berlin hat heute eine Verspätung von fünfzehn Minuten.","question":"Wie viel Verspätung?","options":["5 Min","10 Min","15 Min"],"correct":2,"hint":"Fünfzehn."},{"prompt":"Achtung! Der Zug nach Frankfurt hält nicht in dieser Station.","question":"Was macht der Zug?","options":["Hält","Hält nicht","Fährt zurück"],"correct":1,"hint":"Hält nicht."},{"prompt":"Der ICE nach Köln fährt um 14:30 Uhr ab.","question":"Wann fährt der Zug ab?","options":["14:00 Uhr","14:30 Uhr","15:00 Uhr"],"correct":1,"hint":"Vierzehn Uhr dreißig."},{"prompt":"Der Zug nach Stuttgart ist aufgrund von technischen Problemen verspätet.","question":"Warum hat der Zug Verspätung?","options":["Wetter","Technische Probleme","Unfall"],"correct":1,"hint":"Technische Probleme."},{"prompt":"Gleis zwei. Der Nachtzug nach Wien fährt in wenigen Minuten ab.","question":"Welches Gleis?","options":["1","2","3"],"correct":1,"hint":"Zwei."},{"prompt":"Der Regionalzug nach Bremen wurde auf Gleis fünf umgeleitet.","question":"Auf welches Gleis wurde der Zug umgeleitet?","options":["Gleis vier","Gleis fünf","Gleis sechs"],"correct":1,"hint":"Fünf."},{"prompt":"Bitte beachten Sie, dass der Zug nach Düsseldorf ausfällt.","question":"Was ist mit dem Zug nach Düsseldorf?","options":["Fährt pünktlich","Fällt aus","Hat Verspätung"],"correct":1,"hint":"Fällt aus."},{"prompt":"Der Intercity nach Nürnberg hat eine Verspätung von zwei Minuten.","question":"Wie viel Verspätung hat der Intercity?","options":["1 Min","2 Min","3 Min"],"correct":1,"hint":"Zwei."},{"prompt":"Achtung! Der Zug fährt gleich ab.","question":"Was sollte man beachten?","options":["Der Zug kommt","Der Zug fährt ab","Der Zug hat Verspätung"],"correct":1,"hint":"Fährt ab."},{"prompt":"Der Zug nach Leipzig hat heute eine Verspätung von zehn Minuten.","question":"Wie viel Verspätung hat der Zug?","options":["5 Min","10 Min","20 Min"],"correct":1,"hint":"Zehn."},{"prompt":"Der Zug nach Mannheim fährt jetzt von Gleis drei.","question":"Von welchem Gleis fährt der Zug?","options":["Gleis zwei","Gleis drei","Gleis vier"],"correct":1,"hint":"Drei."},{"prompt":"Der Regionalexpress nach Freiburg ist überfüllt.","question":"Wie ist der Zustand des Zuges?","options":["Leer","Überfüllt","Pünktlich"],"correct":1,"hint":"Überfüllt."},{"prompt":"Der Zug aus München hat eine Verspätung von dreißig Minuten.","question":"Wie viel Verspätung hat der Zug?","options":["20 Min","30 Min","40 Min"],"correct":1,"hint":"Dreißig."},{"prompt":"Bitte beachten Sie die Ansage: Der Zug nach Bonn hat technische Probleme.","question":"Was hat der Zug nach Bonn?","options":["Hat Verspätung","Fährt pünktlich","Technische Probleme"],"correct":2,"hint":"Technische Probleme."},{"prompt":"Gleis sieben. Der Zug nach Salzburg fährt in fünf Minuten ab.","question":"Wann fährt der Zug ab?","options":["In 5 Min","In 10 Min","In 15 Min"],"correct":0,"hint":"Fünf Minuten."}]}', 12),
('de', 'A2', 'listening', 'Ein kurzes Interview', 'A Short Interview', 'Hören Sie Meinungen zu einem Thema.', 'Listen to opinions on a topic.', '{"type":"listen_and_choose","instructions":"Was sagt die Person?","exercises":[{"prompt":"Ich finde, dass Radfahren in der Stadt sehr gesund ist.","question":"Meinung über Radfahren?","options":["Gefährlich","Gesund","Teuer"],"correct":1,"hint":"Gesund (healthy)."},{"prompt":"Aber es gibt leider zu wenige Radwege im Zentrum.","question":"Was ist das Problem?","options":["Zu viele Autos","Zu wenige Radwege"],"correct":1,"hint":"Radwege (cycle paths)."},{"prompt":"Ich fahre jeden Tag mit dem Fahrrad zur Arbeit.","question":"Wie oft fährt sie?","options":["Jeden Tag","Nur am Wochenende"],"correct":0,"hint":"Jeden Tag."},{"prompt":"Das dauert nur fünfzehn Minuten.","question":"Dauer?","options":["15 Min","50 Min"],"correct":0,"hint":"Fünfzehn."},{"prompt":"Ich brauche kein Fitnessstudio mehr.","question":"Warum kein Fitnessstudio?","options":["Zu teuer","Wegen dem Radfahren"],"correct":1,"hint":"Context check."},{"prompt":"Ich genieße es, am Sonntag im Park zu joggen.","question":"Wann joggt die Person?","options":["Jeden Tag","Am Sonntag"],"correct":1,"hint":"Am Sonntag."},{"prompt":"Die Luftqualität in der Stadt könnte besser sein.","question":"Wie ist die Luftqualität?","options":["Sehr gut","Könnte besser sein"],"correct":1,"hint":"Könnte besser sein (could be better)."},{"prompt":"Ich gehe oft schwimmen, weil es mir Spaß macht.","question":"Warum geht sie schwimmen?","options":["Weil es gesund ist","Weil es Spaß macht"],"correct":1,"hint":"Spaß macht (is fun)."},{"prompt":"Es gibt viele Fitnessstudios in der Umgebung.","question":"Was gibt es in der Umgebung?","options":["Fitnessstudios","Restaurants"],"correct":0,"hint":"Fitnessstudios (gyms)."},{"prompt":"Ich finde es wichtig, regelmäßig Sport zu treiben.","question":"Wie wichtig ist Sport für sie?","options":["Nicht wichtig","Wichtig"],"correct":1,"hint":"Wichtig (important)."},{"prompt":"Mein Lieblingssport ist Tennis, weil es schnell ist.","question":"Welcher Sport mag sie?","options":["Fußball","Tennis"],"correct":1,"hint":"Lieblingssport (favorite sport)."},{"prompt":"Ich plane, im nächsten Monat einen Marathon zu laufen.","question":"Was plant sie?","options":["Einen Marathon","Einen Urlaub"],"correct":0,"hint":"Marathon (marathon)."},{"prompt":"Yoga hilft mir, mich zu entspannen.","question":"Was hilft ihr zu entspannen?","options":["Yoga","Lesen"],"correct":0,"hint":"Entspannen (relax)."},{"prompt":"Ich gehe oft mit Freunden wandern.","question":"Mit wem geht sie wandern?","options":["Alleine","Mit Freunden"],"correct":1,"hint":"Mit Freunden (with friends)."},{"prompt":"Das Essen nach dem Sport ist sehr wichtig.","question":"Was ist wichtig nach dem Sport?","options":["Essen","Schlafen"],"correct":0,"hint":"Essen (food)."},{"prompt":"Ich habe ein neues Fahrrad gekauft, um mehr zu fahren.","question":"Warum hat sie ein neues Fahrrad gekauft?","options":["Um mehr zu fahren","Um weniger zu fahren"],"correct":0,"hint":"Mehr fahren (to ride more)."},{"prompt":"Ich finde die Fitnesskurse sehr motivierend.","question":"Wie findet sie die Fitnesskurse?","options":["Langweilig","Motivierend"],"correct":1,"hint":"Motivierend (motivating)."},{"prompt":"Frühstück ist die wichtigste Mahlzeit des Tages.","question":"Welche Mahlzeit ist wichtig?","options":["Mittagessen","Frühstück"],"correct":1,"hint":"Wichtigste Mahlzeit (most important meal)."},{"prompt":"Ich versuche, jeden Tag mindestens eine Stunde zu laufen.","question":"Wie lange läuft sie jeden Tag?","options":["30 Minuten","Eine Stunde"],"correct":1,"hint":"Mindestens eine Stunde (at least one hour)."},{"prompt":"Ich entspanne gerne bei einem guten Buch.","question":"Wie entspannt sie?","options":["Bei einem Film","Bei einem guten Buch"],"correct":1,"hint":"Gutes Buch (good book)."}]}', 13),
('de', 'A2', 'listening', 'Im Reisebüro', 'At the Travel Agency', 'Hören Sie ein Beratungsgespräch.', 'Listen to a consultation.', '{"type":"listen_and_choose","instructions":"Wohin geht die Reise?","exercises":[{"prompt":"Ich möchte im Sommer nach Italien fliegen.","question":"Ziel?","options":["Spanien","Italien","Griechenland"],"correct":1,"hint":"Land im Süden."},{"prompt":"Am liebsten an die Küste, in ein Hotel mit Pool.","question":"Wo?","options":["Berge","Küste"],"correct":1,"hint":"Küste (coast)."},{"prompt":"Wir sind zwei Erwachsene und ein Kind.","question":"Wie viele Personen?","options":["2","3","4"],"correct":1,"hint":"Rechnen Sie."},{"prompt":"Das Angebot inklusive Flug kostet 1200 Euro.","question":"Preis?","options":["1000","1100","1200"],"correct":2,"hint":"Tausend zweihundert."},{"prompt":"Ist das Frühstück im Preis enthalten?","question":"Was fragt der Kunde?","options":["Mittagessen","Frühstück"],"correct":1,"hint":"Mahlzeit am Morgen."},{"prompt":"Ich plane eine Reise nach Frankreich im Frühling.","question":"Ziel?","options":["Frankreich","Deutschland","Österreich"],"correct":0,"hint":"Land der Eiffelturms."},{"prompt":"Wir möchten im Winter nach Skandinavien fahren.","question":"Wann?","options":["Frühling","Sommer","Winter"],"correct":2,"hint":"Kalte Monate."},{"prompt":"Ich interessiere mich für eine Städtereise nach Berlin.","question":"Art der Reise?","options":["Naturreise","Strandurlaub","Städtereise"],"correct":2,"hint":"Große Stadt in Deutschland."},{"prompt":"Wir möchten in die Schweiz wandern gehen.","question":"Aktivität?","options":["Wandern","Schwimmen","Skifahren"],"correct":0,"hint":"In den Bergen."},{"prompt":"Ich möchte nach Spanien reisen und die Kultur erleben.","question":"Was möchte ich erleben?","options":["Essen","Kultur","Sport"],"correct":1,"hint":"Traditionen und Bräuche."},{"prompt":"Wir planen eine Reise nach Griechenland im August.","question":"Wann?","options":["August","Dezember","Oktober"],"correct":0,"hint":"Sommermonat."},{"prompt":"Ich möchte nach Australien fliegen und die Natur sehen.","question":"Was möchte ich sehen?","options":["Kultur","Essen","Natur"],"correct":2,"hint":"Tiere und Landschaften."},{"prompt":"Wir reisen mit dem Auto nach Italien für die Ferien.","question":"Wie reisen wir?","options":["Flugzeug","Zug","Auto"],"correct":2,"hint":"Auf der Straße."},{"prompt":"Ich möchte eine Kreuzfahrt im Mittelmeer machen.","question":"Art der Reise?","options":["Kreuzfahrt","Camping","Städtereise"],"correct":0,"hint":"Auf einem Schiff."},{"prompt":"Wir fliegen nach Kanada, um die Wälder zu erkunden.","question":"Was wollen wir erkunden?","options":["Wälder","Städte","Strände"],"correct":0,"hint":"In der Natur."},{"prompt":"Ich möchte nach Japan reisen und die Tempel besuchen.","question":"Was möchte ich besuchen?","options":["Tempel","Strände","Berge"],"correct":0,"hint":"Religiöse Stätten."},{"prompt":"Wir wollen nach Portugal fahren, um die Strände zu genießen.","question":"Was wollen wir genießen?","options":["Berge","Städte","Strände"],"correct":2,"hint":"Am Wasser."},{"prompt":"Ich plane eine Reise nach Ägypten, um die Pyramiden zu sehen.","question":"Was möchte ich sehen?","options":["Pyramiden","Berge","Seen"],"correct":0,"hint":"Antike Bauwerke."}]}', 14),
('de', 'A2', 'listening', 'Über Hobbys sprechen', 'Talking about Hobbies', 'Hören Sie detaillierte Freizeitaktivitäten.', 'Listen to detailed leisure activities.', '{"type":"listen_and_choose","instructions":"Was ist das Hobby?","exercises":[{"prompt":"Ich lerne seit drei Monaten, Gitarre zu spielen.","question":"Instrument?","options":["Klavier","Gitarre"],"correct":1,"hint":"Saiteninstrument."},{"prompt":"Es ist am Anfang schwierig, aber es macht Spaß.","question":"Ist es leicht?","options":["Ja","Nein"],"correct":1,"hint":"Schwierig (difficult)."},{"prompt":"Ich übe jeden Abend eine halbe Stunde.","question":"Wie lange?","options":["15 Min","30 Min","60 Min"],"correct":1,"hint":"Halbe Stunde."},{"prompt":"Mein Ziel ist es, bald in einer Band zu spielen.","question":"Ziel?","options":["Lehrer werden","In einer Band spielen"],"correct":1,"hint":"Band."},{"prompt":"Nächste Woche habe ich mein erstes kleines Konzert.","question":"Wann ist das Konzert?","options":["Diese Woche","Nächste Woche"],"correct":1,"hint":"Zeitangabe."},{"prompt":"Ich male gerne Landschaften in meiner Freizeit.","question":"Was ist das Hobby?","options":["Fotografieren","Malerei"],"correct":1,"hint":"Mit Farben und Pinsel."},{"prompt":"Am Wochenende gehe ich oft wandern.","question":"Was mache ich am Wochenende?","options":["Wandern","Schwimmen"],"correct":0,"hint":"In der Natur unterwegs."},{"prompt":"Ich spiele regelmäßig Fußball mit meinen Freunden.","question":"Welches Sportspiel spiele ich?","options":["Basketball","Fußball"],"correct":1,"hint":"Mit einem runden Ball."},{"prompt":"Ich habe eine Sammlung von alten Münzen.","question":"Was sammle ich?","options":["Bücher","Münzen"],"correct":1,"hint":"Wertvolle Objekte."},{"prompt":"Ich mache jeden Sonntag Yoga.","question":"Was praktiziere ich?","options":["Yoga","Pilates"],"correct":0,"hint":"Für Entspannung und Flexibilität."},{"prompt":"Ich schreibe Gedichte in meiner Freizeit.","question":"Was tue ich gerne?","options":["Zeichnen","Schreiben"],"correct":1,"hint":"Kreative Texte."},{"prompt":"Ich liebe es, neue Rezepte auszuprobieren.","question":"Was mache ich gerne?","options":["Kochen","Backen"],"correct":0,"hint":"In der Küche aktiv."},{"prompt":"Ich spiele Schach mit meinem Opa.","question":"Welches Spiel spiele ich?","options":["Schach","Dame"],"correct":0,"hint":"Denkspiel auf einem Brett."},{"prompt":"Ich gehe gerne ins Fitnessstudio.","question":"Was mache ich für meine Fitness?","options":["Laufen","Fitness"],"correct":1,"hint":"Trainieren mit Geräten."},{"prompt":"Ich reise gerne in verschiedene Länder.","question":"Was mache ich gerne?","options":["Reisen","Lesen"],"correct":0,"hint":"Entdecken von neuen Orten."},{"prompt":"Ich mache oft Musik mit Freunden.","question":"Was mache ich mit Freunden?","options":["Musik machen","Filme schauen"],"correct":0,"hint":"Gemeinsam musizieren."},{"prompt":"Ich interessiere mich für Astronomie.","question":"Wofür interessiere ich mich?","options":["Astronomie","Biologie"],"correct":0,"hint":"Sterne und Planeten."},{"prompt":"Ich habe einen Garten, in dem ich Pflanzen züchte.","question":"Was mache ich im Garten?","options":["Pflanzen züchten","Spielen"],"correct":0,"hint":"Grüne Daumen."},{"prompt":"Ich mache gerne Fotos von der Natur.","question":"Was mache ich mit einer Kamera?","options":["Malerei","Fotografie"],"correct":1,"hint":"Bilder aufnehmen."},{"prompt":"Ich übe regelmäßig Klavier.","question":"Welches Instrument spiele ich?","options":["Gitarre","Klavier"],"correct":1,"hint":"Tasteninstrument."}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, title_translation, description, description_translation, content, order_index) VALUES
('de', 'A2', 'speaking', 'Vergangenheit erzählen (Perfekt)', 'Narrating Past (Perfekt)', 'Erzählen Sie, was Sie gemacht haben.', 'Tell what you have done.', '{"type":"speak_and_repeat","instructions":"Wiederholen Sie den Satz im Perfekt.","exercises":[{"prompt":"Ich habe gestern eine Pizza gegessen.","expected":"ich habe gestern eine pizza gegessen","hint":"Essen -> gegessen."},{"prompt":"Wir sind am Wochenende nach Hamburg gefahren.","expected":"wir sind am wochenende nach hamburg gefahren","hint":"Fahren -> gefahren (mit sein)."},{"prompt":"Er hat den ganzen Tag hart gearbeitet.","expected":"er hat den ganzen tag hart gearbeitet","hint":"Arbeiten -> gearbeitet."},{"prompt":"Ich bin heute Morgen im Park gejoggt.","expected":"ich bin heute morgen im park gejoggt","hint":"Joggen -> gejoggt (mit sein)."},{"prompt":"Habt ihr den Film schon gesehen?","expected":"habt ihr den film schon gesehen","hint":"Sehen -> gesehen."},{"prompt":"Sie hat letzte Woche ein Buch gelesen.","expected":"sie hat letzte woche ein buch gelesen","hint":"Lesen -> gelesen."},{"prompt":"Wir haben im Urlaub viele Fotos gemacht.","expected":"wir haben im urlaub viele fotos gemacht","hint":"Machen -> gemacht."},{"prompt":"Er ist gestern ins Kino gegangen.","expected":"er ist gestern ins kino gegangen","hint":"Gehen -> gegangen (mit sein)."},{"prompt":"Ich habe heute Morgen gefrühstückt.","expected":"ich habe heute morgen gefrühstückt","hint":"Frühstücken -> gefrühstückt."},{"prompt":"Sie sind im Sommer nach Italien gereist.","expected":"sie sind im sommer nach italien gereist","hint":"Reisen -> gereist (mit sein)."},{"prompt":"Wir haben das Spiel gewonnen.","expected":"wir haben das spiel gewonnen","hint":"Gewinnen -> gewonnen."},{"prompt":"Er hat seine Hausaufgaben gemacht.","expected":"er hat seine hausaufgaben gemacht","hint":"Machen -> gemacht."},{"prompt":"Ich bin vor einer Stunde angekommen.","expected":"ich bin vor einer stunde angekommen","hint":"Ankommen -> angekommen (mit sein)."},{"prompt":"Sie hat ihre Freunde besucht.","expected":"sie hat ihre freunde besucht","hint":"Besuchen -> besucht."},{"prompt":"Wir sind am Freitag ausgegangen.","expected":"wir sind am freitag ausgegangen","hint":"Ausgehen -> ausgegangen (mit sein)."},{"prompt":"Er hat das Auto repariert.","expected":"er hat das auto repariert","hint":"Reparieren -> repariert."},{"prompt":"Ich habe viel gearbeitet.","expected":"ich habe viel gearbeitet","hint":"Arbeiten -> gearbeitet."},{"prompt":"Sie sind den ganzen Tag spazieren gegangen.","expected":"sie sind den ganzen tag spazieren gegangen","hint":"Spazieren gehen -> spazieren gegangen (mit sein)."},{"prompt":"Wir haben einen Film geschaut.","expected":"wir haben einen film geschaut","hint":"Schauen -> geschaut."},{"prompt":"Er hat seine Meinung gesagt.","expected":"er hat seine meinung gesagt","hint":"Sagen -> gesagt."}]}', 11),
('de', 'A2', 'speaking', 'Gründe nennen mit "weil"', 'Giving Reasons with "weil"', 'Bilden Sie Sätze mit weil.', 'Form sentences with weil.', '{"type":"speak_and_repeat","instructions":"Sprechen Sie den Satz mit Grund.","exercises":[{"prompt":"Ich bin müde, weil ich nicht geschlafen habe.","expected":"ich bin muede weil ich nicht geschlafen habe","hint":"Reason for tiredness."},{"prompt":"Wir bleiben zu Hause, weil es regnet.","expected":"wir bleiben zu hause weil es regnet","hint":"Reason for stay."},{"prompt":"Er lernt Deutsch, weil er in Deutschland arbeiten möchte.","expected":"er lernt deutsch weil er in deutschland arbeiten moechte","hint":"Motivation."},{"prompt":"Ich esse nichts, weil ich keinen Hunger habe.","expected":"ich esse nichts weil ich keinen hunger habe","hint":"No hunger."},{"prompt":"Sie ist glücklich, weil sie Geburtstag hat.","expected":"sie ist gluecklich weil sie geburtstag hat","hint":"Happy reason."},{"prompt":"Sie geht ins Kino, weil sie den neuen Film sehen möchte.","expected":"sie geht ins kino weil sie den neuen film sehen moechte","hint":"Interest in a movie."},{"prompt":"Ich esse einen Apfel, weil ich gesund bleiben möchte.","expected":"ich esse einen apfel weil ich gesund bleiben moechte","hint":"Health reason."},{"prompt":"Wir fahren in den Urlaub, weil wir uns entspannen wollen.","expected":"wir fahren in den urlaub weil wir uns entspannen wollen","hint":"Desire to relax."},{"prompt":"Er kauft ein neues Auto, weil sein altes kaputt ist.","expected":"er kauft ein neues auto weil sein altes kaputt ist","hint":"Need for a vehicle."},{"prompt":"Sie studiert Medizin, weil sie Ärztin werden möchte.","expected":"sie studiert medizin weil sie aerztin werden moechte","hint":"Career aspiration."},{"prompt":"Ich trinke Kaffee, weil ich müde bin.","expected":"ich trinke kaffee weil ich muede bin","hint":"Need for energy."},{"prompt":"Wir machen eine Party, weil wir den Geburtstag feiern.","expected":"wir machen eine party weil wir den geburtstag feiern","hint":"Celebration reason."},{"prompt":"Er liest ein Buch, weil er mehr Wissen haben möchte.","expected":"er liest ein buch weil er mehr wissen haben moechte","hint":"Desire for knowledge."},{"prompt":"Sie läuft jeden Morgen, weil sie fit bleiben will.","expected":"sie laeuft jeden morgen weil sie fit bleiben will","hint":"Fitness goal."},{"prompt":"Ich lerne Englisch, weil ich im Ausland arbeiten möchte.","expected":"ich lerne englisch weil ich im ausland arbeiten moechte","hint":"Job opportunity."},{"prompt":"Wir essen im Restaurant, weil wir keine Zeit zum Kochen haben.","expected":"wir essen im restaurant weil wir keine zeit zum kochen haben","hint":"Lack of time."},{"prompt":"Er fährt mit dem Fahrrad, weil er die Umwelt schützen möchte.","expected":"er faehrt mit dem fahrrad weil er die umwelt schuetzen moechte","hint":"Environmental concern."},{"prompt":"Sie nimmt den Bus, weil sie ihr Auto nicht finden kann.","expected":"sie nimmt den bus weil sie ihr auto nicht finden kann","hint":"Difficulty with transportation."},{"prompt":"Ich mache Sport, weil ich abnehmen möchte.","expected":"ich mache sport weil ich abnehmen moechte","hint":"Weight loss goal."},{"prompt":"Wir gehen früh ins Bett, weil wir morgen früh aufstehen müssen.","expected":"wir gehen frueh ins bett weil wir morgen frueh aufstehen muessen","hint":"Need for rest."}]}', 12),
('de', 'A2', 'speaking', 'Modalverben im Alltag', 'Modal Verbs in Daily Life', 'Wünsche und Pflichten ausdrücken.', 'Expressing wishes and duties.', '{"type":"speak_and_repeat","instructions":"Benutzen Sie das Modalverb.","exercises":[{"prompt":"Ich muss heute noch einkaufen gehen.","expected":"ich muss heute noch einkaufen gehen","hint":"Müssen (obligation)."},{"prompt":"Kannst du mir bitte beim Kochen helfen?","expected":"kannst du mir bitte beim kochen helfen","hint":"Können (ability/request)."},{"prompt":"Wir wollen am Samstag ins Kino gehen.","expected":"wir wollen am samstag ins kino gehen","hint":"Wollen (intention)."},{"prompt":"Darf ich hier mein Auto parken?","expected":"darf ich hier mein auto parken","hint":"Dürfen (permission)."},{"prompt":"Man soll jeden Tag viel Wasser trinken.","expected":"man soll jeden tag viel wasser trinken","hint":"Sollen (suggestion)."},{"prompt":"Ich darf heute Abend nicht spät nach Hause kommen.","expected":"ich darf heute abend nicht spät nach hause kommen","hint":"Dürfen (permission)."},{"prompt":"Er möchte ein neues Fahrrad kaufen.","expected":"er möchte ein neues fahrrad kaufen","hint":"Möchten (wish/request)."},{"prompt":"Könnte ich bitte das Fenster öffnen?","expected":"könnte ich bitte das fenster öffnen","hint":"Können (polite request)."},{"prompt":"Wir müssen für die Prüfung lernen.","expected":"wir müssen für die prüfung lernen","hint":"Müssen (necessity)."},{"prompt":"Du sollst mehr Wasser trinken.","expected":"du sollst mehr wasser trinken","hint":"Sollen (advice)."},{"prompt":"Ich kann gut schwimmen.","expected":"ich kann gut schwimmen","hint":"Können (ability)."},{"prompt":"Sie will heute Abend ins Theater gehen.","expected":"sie will heute abend ins theater gehen","hint":"Wollen (intention)."},{"prompt":"Darf ich Ihnen meine Hilfe anbieten?","expected":"darf ich ihnen meine hilfe anbieten","hint":"Dürfen (offer)."},{"prompt":"Wir möchten einen Tisch für zwei reservieren.","expected":"wir möchten einen tisch für zwei reservieren","hint":"Möchten (wish/request)."},{"prompt":"Er kann sehr gut zeichnen.","expected":"er kann sehr gut zeichnen","hint":"Können (ability)."},{"prompt":"Ich muss morgen früh aufstehen.","expected":"ich muss morgen früh aufstehen","hint":"Müssen (obligation)."},{"prompt":"Du solltest deine Hausaufgaben machen.","expected":"du solltest deine hausaufgaben machen","hint":"Sollen (advice)."},{"prompt":"Könnten wir bitte die Rechnung haben?","expected":"könnten wir bitte die rechnung haben","hint":"Können (polite request)."},{"prompt":"Sie dürfen hier nicht rauchen.","expected":"sie dürfen hier nicht rauchen","hint":"Dürfen (prohibition)."},{"prompt":"Ich will den neuen Film sehen.","expected":"ich will den neuen film sehen","hint":"Wollen (desire)."}]}', 13),
('de', 'A2', 'speaking', 'Wegbeschreibung detailliert', 'Detailed Directions', 'Den Weg genau erklären.', 'Explain the way exactly.', '{"type":"speak_and_repeat","instructions":"Erklären Sie den Weg.","exercises":[{"prompt":"Gehen Sie die Straße entlang bis zur Kreuzung.","expected":"gehen sie die strasse entlang bis zur kreuzung","hint":"Go along to intersection."},{"prompt":"Biegen Sie nach der Kirche scharf links ab.","expected":"biegen sie nach der kirche scharf links ab","hint":"Turn sharp left after church."},{"prompt":"Das Museum ist direkt hinter dem großen Parkplatz.","expected":"das museum ist direkt hinter dem grossen parkplatz","hint":"Behind parking lot."},{"prompt":"Nehmen Sie die U-Bahn Linie drei Richtung Zentrum.","expected":"nehmen sie die u bahn linie drei richtung zentrum","hint":"Subway description."},{"prompt":"Sie sehen das Gebäude auf der rechten Seite.","expected":"sie sehen das gebaeude auf der rechten seite","hint":"On the right side."},{"prompt":"Gehen Sie geradeaus bis zur Ampel.","expected":"gehen sie geradeaus bis zur ampel","hint":"Go straight to the traffic light."},{"prompt":"Nehmen Sie die erste Straße rechts.","expected":"nehmen sie die erste strasse rechts","hint":"Take the first street on the right."},{"prompt":"Das Hotel ist neben der Bank.","expected":"das hotel ist neben der bank","hint":"Next to the bank."},{"prompt":"Biegen Sie an der nächsten Kreuzung links ab.","expected":"biegen sie an der naechsten kreuzung links ab","hint":"Turn left at the next intersection."},{"prompt":"Das Restaurant liegt gegenüber dem Supermarkt.","expected":"das restaurant liegt gegenueber dem supermarkt","hint":"Opposite the supermarket."},{"prompt":"Folgen Sie der Straße bis zum Platz.","expected":"folgen sie der strasse bis zum platz","hint":"Follow the road to the square."},{"prompt":"Gehen Sie die Treppe hinunter.","expected":"gehen sie die treppe hinunter","hint":"Go down the stairs."},{"prompt":"Biegen Sie nach rechts an der zweiten Ecke ab.","expected":"biegen sie nach rechts an der zweiten ecke ab","hint":"Turn right at the second corner."},{"prompt":"Das Café ist in der Nähe der Universität.","expected":"das cafe ist in der naehe der universitaet","hint":"Near the university."},{"prompt":"Fahren Sie bis zur Autobahn.","expected":"fahren sie bis zur autobahn","hint":"Drive to the highway."},{"prompt":"Das Kino ist zwei Blocks weiter.","expected":"das kino ist zwei blocks weiter","hint":"Two blocks further."},{"prompt":"Biegen Sie links ab, bevor Sie die Brücke erreichen.","expected":"biegen sie links ab bevor sie die bruecke erreichen","hint":"Turn left before you reach the bridge."},{"prompt":"Das Fitnessstudio ist über der Apotheke.","expected":"das fitnessstudio ist ueber der apotheke","hint":"Above the pharmacy."},{"prompt":"Gehen Sie nach dem Park nach rechts.","expected":"gehen sie nach dem park nach rechts","hint":"Turn right after the park."},{"prompt":"Das Büro befindet sich im dritten Stock.","expected":"das buero befindet sich im dritten stock","hint":"Located on the third floor."}]}', 14),
('de', 'A2', 'speaking', 'Ein Zimmer beschreiben', 'Describing a Room', 'Präpositionen benutzen.', 'Using prepositions.', '{"type":"speak_and_repeat","instructions":"Wo stehen die Möbel?","exercises":[{"prompt":"Der Teppich liegt unter dem runden Tisch.","expected":"der teppich liegt unter dem runden tisch","hint":"Under the round table."},{"prompt":"Das Bild hängt über dem Sofa an der Wand.","expected":"das bild haengt ueber dem sofa an der wand","hint":"Above sofa on wall."},{"prompt":"Die Lampe steht zwischen dem Bett und dem Schrank.","expected":"die lampe steht zwischen dem bett und dem schrank","hint":"Between bed and closet."},{"prompt":"Stell die Blumen bitte in die Vase auf dem Fensterbrett.","expected":"stell die blumen bitte in die vase auf dem fensterbrett","hint":"In the vase on windowsill."},{"prompt":"Neben dem Fernseher steht ein großes Bücherregal.","expected":"neben dem fernseher steht ein grosses buecherregal","hint":"Next to TV."},{"prompt":"Der Stuhl steht neben dem Tisch.","expected":"der stuhl steht neben dem tisch","hint":"Next to the table."},{"prompt":"Die Bücher liegen auf dem Regal.","expected":"die buecher liegen auf dem regal","hint":"On the shelf."},{"prompt":"Der Fernseher steht gegenüber dem Sofa.","expected":"der fernseher steht gegenueber dem sofa","hint":"Across from the sofa."},{"prompt":"Die Vase steht auf dem Tisch.","expected":"die vase steht auf dem tisch","hint":"On the table."},{"prompt":"Die Couch steht in der Ecke des Raumes.","expected":"die couch steht in der ecke des raumes","hint":"In the corner of the room."},{"prompt":"Der Kühlschrank steht neben dem Herd.","expected":"der kuehlschrank steht neben dem herd","hint":"Next to the stove."},{"prompt":"Der Spiegel hängt über dem Waschbecken.","expected":"der spiegel haengt ueber dem waschbecken","hint":"Above the sink."},{"prompt":"Der Sessel steht vor dem Fenster.","expected":"der sessel steht vor dem fenster","hint":"In front of the window."},{"prompt":"Die Kommode steht an der Wand.","expected":"die kommode steht an der wand","hint":"Against the wall."},{"prompt":"Der Tisch steht in der Mitte des Raumes.","expected":"der tisch steht in der mitte des raumes","hint":"In the middle of the room."},{"prompt":"Die Pflanzen stehen auf dem Balkon.","expected":"die pflanzen stehen auf dem balkon","hint":"On the balcony."},{"prompt":"Die Decke hängt an der Decke.","expected":"die decke haengt an der decke","hint":"Hanging from the ceiling."},{"prompt":"Der Teppich liegt vor dem Sofa.","expected":"der teppich liegt vor dem sofa","hint":"In front of the sofa."},{"prompt":"Die Uhr hängt an der Wand.","expected":"die uhr haengt an der wand","hint":"On the wall."},{"prompt":"Die Stühle stehen um den Tisch.","expected":"die stuehle stehen um den tisch","hint":"Around the table."}]}', 15);
