('de', 'A2', 'reading', 'Ein Reisebericht aus Island', 'A Travel Report from Iceland', 'Lesen Sie über die Natur Islands.', 'Read about Iceland''s nature.', '{"type":"read_and_choose","instructions":"Beantworten Sie die Fragen zum Text.","exercises":[{"sentence":"Island ist bekannt für seine Vulkane, Gletscher und heißen Quellen.","question":"Was gibt es in Island?","options":["Urwald","Gletscher","Wüste"],"correct":1,"explanation":"Gletscher werden genannt."},{"sentence":"Wir haben eine Tour mit einem Jeep durch das Hochland gemacht.","question":"Wie sind sie gereist?","options":["Mit dem Fahrrad","Mit einem Jeep"],"correct":1,"explanation":"Tour mit einem Jeep."},{"sentence":"Die Wasserfälle sind beeindruckend und sehr kraftvoll.","question":"Wie findet der Autor die Wasserfälle?","options":["Langweilig","Beeindruckend"],"correct":1,"explanation":"Beeindruckend (impressive)."},{"sentence":"Das Wetter wechselt oft mehrmals pro Stunde zwischen Sonne und Regen.","question":"Ist das Wetter stabil?","options":["Ja","Nein"],"correct":1,"explanation":"Wechselt oft."},{"sentence":"In den kleinen Fischerdörfern kann man frischen Fisch essen.","question":"Was isst man dort?","options":["Fleisch","Fisch"],"correct":1,"explanation":"Frischen Fisch."},{"sentence":"Die Nordlichter sind ein faszinierendes Naturphänomen, das in Island oft zu sehen ist.","question":"Was kann man in Island oft sehen?","options":["Regenbogen","Nordlichter"],"correct":1,"explanation":"Nordlichter werden erwähnt."},{"sentence":"Die heißen Quellen sind perfekt zum Entspannen nach einem langen Tag.","question":"Warum sind die heißen Quellen beliebt?","options":["Zum Entspannen","Zum Schwimmen"],"correct":0,"explanation":"Sie sind perfekt zum Entspannen."},{"sentence":"In Island gibt es viele malerische Dörfer mit bunten Häusern.","question":"Wie sind die Häuser in den Dörfern?","options":["Bunt","Graubraun"],"correct":0,"explanation":"Die Häuser sind bunt."},{"sentence":"Die isländische Küche ist bekannt für frischen Fisch und Lammfleisch.","question":"Was ist ein typisches Lebensmittel in Island?","options":["Frischer Fisch","Tacos"],"correct":0,"explanation":"Frischer Fisch wird genannt."},{"sentence":"Island hat eine einzigartige Flora und Fauna, die viele Besucher anzieht.","question":"Was zieht viele Besucher nach Island?","options":["Die Flora und Fauna","Die Wüste"],"correct":0,"explanation":"Flora und Fauna ziehen Besucher an."},{"sentence":"Im Sommer gibt es in Island fast 24 Stunden Tageslicht.","question":"Was passiert im Sommer in Island?","options":["Es gibt wenig Licht","Es gibt fast 24 Stunden Tageslicht"],"correct":1,"explanation":"Es gibt fast 24 Stunden Tageslicht."},{"sentence":"Die isländischen Gletscher sind die größten in Europa.","question":"Wie sind die Gletscher in Island?","options":["Klein","Die größten in Europa"],"correct":1,"explanation":"Sie sind die größten in Europa."},{"sentence":"Die Hauptstadt Reykjavik ist die nördlichste Hauptstadt der Welt.","question":"Was ist besonders an Reykjavik?","options":["Es ist die nördlichste Hauptstadt","Es ist eine große Stadt"],"correct":0,"explanation":"Reykjavik ist die nördlichste Hauptstadt."},{"sentence":"Island hat viele Wanderwege, die zu atemberaubenden Aussichtspunkten führen.","question":"Was bieten die Wanderwege in Island?","options":["Erschöpfung","Atemberaubende Aussichtspunkte"],"correct":1,"explanation":"Sie führen zu atemberaubenden Aussichtspunkten."},{"sentence":"Die Isländer sind stolz auf ihre Kultur und ihre Sagas.","question":"Worauf sind die Isländer stolz?","options":["Ihre Kultur","Ihre Küche"],"correct":0,"explanation":"Sie sind stolz auf ihre Kultur."},{"sentence":"Die Wale vor der Küste Islands sind ein beliebtes Ziel für Touristen.","question":"Was ist ein beliebtes Ziel für Touristen?","options":["Die Wale","Die Berge"],"correct":0,"explanation":"Die Wale vor der Küste sind beliebt."},{"sentence":"Die isländische Sprache hat viele alte Wurzeln und ist sich erhalten geblieben.","question":"Was ist besonders an der isländischen Sprache?","options":["Sie hat alte Wurzeln","Sie ist sehr modern"],"correct":0,"explanation":"Sie hat viele alte Wurzeln."},{"sentence":"In Island kann man oft Schafe auf den Weiden sehen.","question":"Was sieht man oft in Island?","options":["Kühe","Schafe"],"correct":1,"explanation":"Schafe werden erwähnt."},{"sentence":"Die Geothermalenergie ist eine wichtige Energiequelle in Island.","question":"Was ist eine wichtige Energiequelle in Island?","options":["Kohle","Geothermalenergie"],"correct":1,"explanation":"Geothermalenergie ist wichtig."},{"sentence":"Das Wetter in Island kann sehr wechselhaft sein, auch im Sommer.","question":"Wie ist das Wetter in Island?","options":["Stabil","Wechselhaft"],"correct":1,"explanation":"Das Wetter kann wechselhaft sein."}]}', 11),
('de', 'A2', 'reading', 'Hausordnung lesen', 'Reading House Rules', 'Regeln für das Zusammenleben.', 'Rules for living together.', '{"type":"read_and_choose","instructions":"Was ist in diesem Haus erlaubt?","exercises":[{"sentence":"Die Nachtruhe beginnt um 22 Uhr und endet um 7 Uhr morgens.","question":"Darf man um 23 Uhr laut Musik hören?","options":["Ja","Nein"],"correct":1,"explanation":"Nachtruhe ab 22 Uhr."},{"sentence":"Der Müll muss nach Papier, Plastik und Restmüll getrennt werden.","question":"Muss man Müll trennen?","options":["Ja","Nein"],"correct":0,"explanation":"Müll trennen (separate trash)."},{"sentence":"Fahrräder dürfen nicht im Hausflur stehen, sondern nur im Keller.","question":"Wo parkt man das Fahrrad?","options":["Hausflur","Keller"],"correct":1,"explanation":"Nur im Keller."},{"sentence":"Haustiere sind nach Absprache mit dem Vermieter erlaubt.","question":"Darf man einen Hund haben?","options":["Generell verboten","Nach Absprache"],"correct":1,"explanation":"Nach Absprache (after consultation)."},{"sentence":"Das Treppenhaus wird wöchentlich abwechselnd von den Bewohnern gereinigt.","question":"Wer putzt das Treppenhaus?","options":["Eine Firma","Die Bewohner"],"correct":1,"explanation":"Von den Bewohnern gereinigt."},{"sentence":"Haustiere sind in der Wohnung erlaubt, solange sie keinen Lärm machen.","question":"Sind laute Haustiere erlaubt?","options":["Ja","Nein"],"correct":1,"explanation":"Laute Haustiere sind nicht erlaubt."},{"sentence":"Das Rauchen ist im gesamten Gebäude verboten.","question":"Darf man im Gebäude rauchen?","options":["Ja","Nein"],"correct":1,"explanation":"Rauchen ist im gesamten Gebäude verboten."},{"sentence":"Besucher dürfen nur bis 22 Uhr bleiben.","question":"Dürfen Besucher bis nach Mitternacht bleiben?","options":["Ja","Nein"],"correct":1,"explanation":"Besucher müssen bis 22 Uhr gehen."},{"sentence":"Die Treppenhäuser müssen immer frei von Gegenständen sein.","question":"Darf man Dinge im Treppenhaus abstellen?","options":["Ja","Nein"],"correct":1,"explanation":"Das Treppenhaus muss frei bleiben."},{"sentence":"In der Küche darf man nur mit sauberen Händen kochen.","question":"Darf man mit schmutzigen Händen in der Küche kochen?","options":["Ja","Nein"],"correct":1,"explanation":"Kochen mit sauberen Händen ist Pflicht."},{"sentence":"Das Parken ist nur auf den markierten Stellplätzen erlaubt.","question":"Darf man überall parken?","options":["Ja","Nein"],"correct":1,"explanation":"Parken ist nur auf markierten Stellplätzen erlaubt."},{"sentence":"Lärm muss zwischen 22 Uhr und 7 Uhr vermieden werden.","question":"Ist lautes Reden nach 22 Uhr erlaubt?","options":["Ja","Nein"],"correct":1,"explanation":"Lärm muss nach 22 Uhr vermieden werden."},{"sentence":"Der Gemeinschaftsraum kann von allen Bewohnern genutzt werden.","question":"Darf man den Gemeinschaftsraum benutzen?","options":["Ja","Nein"],"correct":0,"explanation":"Der Gemeinschaftsraum ist für alle Bewohner zugänglich."},{"sentence":"Es ist nicht erlaubt, Möbel im Flur abzustellen.","question":"Darf man Möbel im Flur lassen?","options":["Ja","Nein"],"correct":1,"explanation":"Möbel im Flur sind nicht erlaubt."},{"sentence":"Der Grill darf nur im Garten benutzt werden.","question":"Wo darf man den Grill benutzen?","options":["Im Haus","Im Garten"],"correct":1,"explanation":"Der Grill ist nur im Garten erlaubt."},{"sentence":"Lange Partys sind nur am Wochenende erlaubt.","question":"Darf man unter der Woche lange Partys feiern?","options":["Ja","Nein"],"correct":1,"explanation":"Lange Partys sind nur am Wochenende erlaubt."},{"sentence":"Das Wasser darf nicht unnötig verschwendet werden.","question":"Darf man Wasser verschwenden?","options":["Ja","Nein"],"correct":1,"explanation":"Wasserverschwendung ist nicht erlaubt."},{"sentence":"Die Fenster müssen bei Regen geschlossen werden.","question":"Darf man bei Regen die Fenster offen lassen?","options":["Ja","Nein"],"correct":1,"explanation":"Die Fenster müssen bei Regen geschlossen sein."},{"sentence":"Der Aufzug darf nur von zwei Personen gleichzeitig benutzt werden.","question":"Dürfen mehr als zwei Personen den Aufzug benutzen?","options":["Ja","Nein"],"correct":1,"explanation":"Nur zwei Personen dürfen den Aufzug gleichzeitig benutzen."},{"sentence":"Die Haustür muss immer abgeschlossen werden.","question":"Darf die Haustür offen bleiben?","options":["Ja","Nein"],"correct":1,"explanation":"Die Haustür muss immer abgeschlossen sein."}]}', 12),
('de', 'A2', 'reading', 'Gesundheitstipps im Netz', 'Online Health Tips', 'Kurze Ratschläge für den Alltag.', 'Short advice for daily life.', '{"type":"read_and_choose","instructions":"Finden Sie den richtigen Tipp.","exercises":[{"sentence":"Bildschirmpausen sind wichtig, um die Augen zu entspannen.","question":"Wofür sind Pausen wichtig?","options":["Für die Augen","Für die Ohren"],"correct":0,"explanation":"Gegen Augenmüdigkeit."},{"sentence":"Obst und Gemüse enthalten wichtige Vitamine für das Immunsystem.","question":"Was ist in Obst enthalten?","options":["Fett","Vitamine"],"correct":1,"explanation":"Vitamine."},{"sentence":"Tägliche Bewegung an der frischen Luft stärkt das Herz.","question":"Was stärkt das Herz?","options":["Bewegung draußen","Viel Schlafen"],"correct":0,"explanation":"Bewegung an frischer Luft."},{"sentence":"Vermeiden Sie Stress durch gutes Zeitmanagement und Hobbys.","question":"Wie reduziert man Stress?","options":["Mehr Arbeit","Zeitmanagement"],"correct":1,"explanation":"Gutes Zeitmanagement."},{"sentence":"Genug Schlaf (ca. 7-8 Stunden) ist für die Konzentration nötig.","question":"Wie viel Schlaf wird empfohlen?","options":["5 Stunden","7-8 Stunden"],"correct":1,"explanation":"7-8 Stunden."},{"sentence":"Regelmäßiges Trinken ist wichtig für die Gesundheit.","question":"Wofür ist regelmäßiges Trinken wichtig?","options":["Für die Gesundheit","Für die Muskulatur"],"correct":0,"explanation":"Trinken hält den Körper gesund."},{"sentence":"Ausreichend Schlaf verbessert die Konzentration.","question":"Was verbessert ausreichend Schlaf?","options":["Die Konzentration","Die Verdauung"],"correct":0,"explanation":"Schlaf ist wichtig für die geistige Klarheit."},{"sentence":"Die richtige Ernährung fördert das Wohlbefinden.","question":"Was fördert das Wohlbefinden?","options":["Die richtige Ernährung","Viel Fernsehen"],"correct":0,"explanation":"Gesunde Ernährung trägt zum Wohlbefinden bei."},{"sentence":"Stressabbau ist wichtig für die mentale Gesundheit.","question":"Wofür ist Stressabbau wichtig?","options":["Für die mentale Gesundheit","Für die körperliche Fitness"],"correct":0,"explanation":"Stress kann negative Auswirkungen auf die mentale Gesundheit haben."},{"sentence":"Soziale Kontakte sind wichtig für ein erfülltes Leben.","question":"Was ist wichtig für ein erfülltes Leben?","options":["Soziale Kontakte","Alleinsein"],"correct":0,"explanation":"Menschen brauchen soziale Interaktionen."},{"sentence":"Ein gutes Buch zu lesen kann entspannend wirken.","question":"Was kann entspannend wirken?","options":["Ein gutes Buch","Stressige Arbeit"],"correct":0,"explanation":"Lesen fördert die Entspannung."},{"sentence":"Ein Spaziergang in der Natur kann den Geist klären.","question":"Was kann den Geist klären?","options":["Ein Spaziergang in der Natur","Viel Lärm"],"correct":0,"explanation":"Natur fördert die geistige Klarheit."},{"sentence":"Meditation hilft, den Stress abzubauen.","question":"Was hilft beim Stressabbau?","options":["Meditation","Hektik"],"correct":0,"explanation":"Meditation fördert die Entspannung."},{"sentence":"Hobbyaktivitäten können das Leben bereichern.","question":"Was kann das Leben bereichern?","options":["Hobbyaktivitäten","Überarbeitung"],"correct":0,"explanation":"Hobbys machen das Leben bunter."},{"sentence":"Das Trinken von Tee kann beruhigend wirken.","question":"Was kann beruhigend wirken?","options":["Tee","Kaffee"],"correct":0,"explanation":"Tee hat oft eine beruhigende Wirkung."},{"sentence":"Ein gesunder Lebensstil fördert die Lebensqualität.","question":"Was fördert die Lebensqualität?","options":["Ein gesunder Lebensstil","Ungesunde Gewohnheiten"],"correct":0,"explanation":"Gesunde Gewohnheiten verbessern die Lebensqualität."},{"sentence":"Regelmäßige Entspannung ist wichtig für die Stressbewältigung.","question":"Was ist wichtig für die Stressbewältigung?","options":["Regelmäßige Entspannung","Dauerhafte Anspannung"],"correct":0,"explanation":"Entspannung hilft, Stress abzubauen."},{"sentence":"Sportliche Betätigung stärkt die Muskulatur.","question":"Was stärkt die Muskulatur?","options":["Sportliche Betätigung","Viel Sitzen"],"correct":0,"explanation":"Sport ist wichtig für die Muskulatur."},{"sentence":"Gesunde Fette sind wichtig für das Herz.","question":"Was ist wichtig für das Herz?","options":["Gesunde Fette","Zucker"],"correct":0,"explanation":"Gesunde Fette unterstützen die Herzgesundheit."},{"sentence":"Frische Luft ist wichtig für die Lungen.","question":"Was ist wichtig für die Lungen?","options":["Frische Luft","Rauchige Umgebung"],"correct":0,"explanation":"Frische Luft ist entscheidend für die Lungenfunktion."}]}', 13),
('de', 'A2', 'reading', 'Kultur in der Stadt', 'Culture in the City', 'Ein Veranstaltungskalender.', 'A calendar of events.', '{"type":"read_and_choose","instructions":"Wann findet was statt?","exercises":[{"sentence":"Am Freitagabend gibt es ein Jazz-Konzert im Kulturzentrum.","question":"Wann ist das Jazz-Konzert?","options":["Freitag","Samstag"],"correct":0,"explanation":"Am Freitagabend."},{"sentence":"Die Kunstausstellung im Museum ist täglich von 10 bis 18 Uhr offen.","question":"Wann öffnet das Museum?","options":["9 Uhr","10 Uhr"],"correct":1,"explanation":"Ab 10 Uhr."},{"sentence":"Am Sonntag findet auf dem Marktplatz ein Flohmarkt statt.","question":"Wo ist der Flohmarkt?","options":["Museum","Marktplatz"],"correct":1,"explanation":"Auf dem Marktplatz."},{"sentence":"Der Eintritt für das Theaterstück am Samstag kostet 15 Euro.","question":"Preis für Theater?","options":["10 Euro","15 Euro"],"correct":1,"explanation":"Kostet 15 Euro."},{"sentence":"Studenten erhalten bei allen Events einen Rabatt.","question":"Wer zahlt weniger?","options":["Nur Kinder","Studenten"],"correct":1,"explanation":"Studenten erhalten Rabatt."},{"sentence":"Am Mittwochabend findet im Park ein Open-Air-Kino statt.","question":"Wann ist das Open-Air-Kino?","options":["Dienstag","Mittwoch"],"correct":1,"explanation":"Am Mittwochabend."},{"sentence":"Das Theaterstück beginnt am Samstag um 19 Uhr.","question":"Wann beginnt das Theaterstück?","options":["Sonntag","Samstag"],"correct":1,"explanation":"Am Samstag um 19 Uhr."},{"sentence":"Die Buchmesse ist von Freitag bis Sonntag im Messezentrum.","question":"Wie lange dauert die Buchmesse?","options":["Einen Tag","Drei Tage"],"correct":1,"explanation":"Von Freitag bis Sonntag."},{"sentence":"Am Donnerstag gibt es einen Workshop für kreative Fotografie.","question":"Wann ist der Workshop?","options":["Mittwoch","Donnerstag"],"correct":1,"explanation":"Am Donnerstag."},{"sentence":"Der Weihnachtsmarkt eröffnet am ersten Adventswochenende.","question":"Wann eröffnet der Weihnachtsmarkt?","options":["Erster Advent","Zweiter Advent"],"correct":0,"explanation":"Am ersten Adventswochenende."},{"sentence":"Die Sportveranstaltung findet nächsten Sonntag um 15 Uhr statt.","question":"Wann ist die Sportveranstaltung?","options":["Samstag","Sonntag"],"correct":1,"explanation":"Nächsten Sonntag um 15 Uhr."},{"sentence":"Der Yoga-Kurs startet jeden Dienstag um 18 Uhr.","question":"Wann beginnt der Yoga-Kurs?","options":["Montag","Dienstag"],"correct":1,"explanation":"Jeden Dienstag."},{"sentence":"Am Freitag gibt es ein Straßenfest in der Innenstadt.","question":"Wann findet das Straßenfest statt?","options":["Donnerstag","Freitag"],"correct":1,"explanation":"Am Freitag."},{"sentence":"Die Filmvorführung im Kino beginnt um 20 Uhr am Samstag.","question":"Wann ist die Filmvorführung?","options":["Freitag","Samstag"],"correct":1,"explanation":"Um 20 Uhr am Samstag."},{"sentence":"Die Stadtführung startet jeden Sonntag um 10 Uhr.","question":"Wann startet die Stadtführung?","options":["Samstag","Sonntag"],"correct":1,"explanation":"Jeden Sonntag um 10 Uhr."},{"sentence":"Das Konzert findet in der Aula der Schule am Freitagabend statt.","question":"Wo findet das Konzert statt?","options":["Schule","Kulturzentrum"],"correct":0,"explanation":"In der Aula der Schule."},{"sentence":"Die Lesung beginnt am Donnerstag um 19 Uhr im Buchladen.","question":"Wann beginnt die Lesung?","options":["Donnerstag","Freitag"],"correct":0,"explanation":"Am Donnerstag um 19 Uhr."},{"sentence":"Das Festival der Kulturen findet im Sommer statt.","question":"Wann findet das Festival statt?","options":["Im Winter","Im Sommer"],"correct":1,"explanation":"Im Sommer."},{"sentence":"Am Dienstag gibt es ein Seminar über digitale Medien.","question":"Wann ist das Seminar?","options":["Montag","Dienstag"],"correct":1,"explanation":"Am Dienstag."},{"sentence":"Die Eröffnung der neuen Bibliothek ist am 1. Mai.","question":"Wann ist die Eröffnung der Bibliothek?","options":["30. April","1. Mai"],"correct":1,"explanation":"Am 1. Mai."}]}', 14),
('de', 'A2', 'reading', 'Rezept: Apfelkuchen', 'Recipe: Apple Cake', 'Anweisungen für einen Kuchen.', 'Instructions for a cake.', '{"type":"read_and_choose","instructions":"Verstehen Sie die Backanleitung.","exercises":[{"sentence":"Zuerst vermischen Sie Mehl, Zucker und Eier in einer Schüssel.","question":"Was ist der erste Schritt?","options":["Backen","Zutaten mischen"],"correct":1,"explanation":"Zuerst vermischen."},{"sentence":"Schneiden Sie dann drei Äpfel in kleine Stücke.","question":"Wie viele Äpfel braucht man?","options":["2","3","4"],"correct":1,"explanation":"Drei Äpfel."},{"sentence":"Geben Sie den Teig in eine gefettete Form.","question":"In welche Form?","options":["Gefettet","Kalt"],"correct":0,"explanation":"Gefettete Form."},{"sentence":"Backen Sie den Kuchen bei 180 Grad für ca. 45 Minuten.","question":"Backzeit?","options":["30 Min","45 Min","60 Min"],"correct":1,"explanation":"45 Minuten."},{"sentence":"Lassen Sie den Kuchen vor dem Essen gut abkühlen.","question":"Sofort essen?","options":["Ja","Erst abkühlen lassen"],"correct":1,"explanation":"Erst abkühlen lassen."},{"sentence":"Mischen Sie die trockenen Zutaten in einer Schüssel.","question":"Was wird in der Schüssel gemischt?","options":["Nasse Zutaten","Trockene Zutaten"],"correct":1,"explanation":"Die trockenen Zutaten werden gemischt."},{"sentence":"Fügen Sie dann die Milch langsam hinzu.","question":"Was wird langsam hinzugefügt?","options":["Milch","Wasser"],"correct":0,"explanation":"Die Milch wird hinzugefügt."},{"sentence":"Backen Sie den Kuchen bei 180 Grad für 30 Minuten.","question":"Wie lange wird der Kuchen gebacken?","options":["20 Minuten","30 Minuten","40 Minuten"],"correct":1,"explanation":"30 Minuten Backzeit."},{"sentence":"Lassen Sie den Kuchen nach dem Backen abkühlen.","question":"Was soll nach dem Backen gemacht werden?","options":["Kuchen schneiden","Kuchen abkühlen lassen"],"correct":1,"explanation":"Der Kuchen soll abkühlen."},{"sentence":"Verzieren Sie den Kuchen mit Puderzucker.","question":"Womit wird der Kuchen verziert?","options":["Schokolade","Puderzucker"],"correct":1,"explanation":"Der Kuchen wird mit Puderzucker verziert."},{"sentence":"Rühren Sie den Teig gut durch, bis er glatt ist.","question":"Was muss mit dem Teig gemacht werden?","options":["Durchrühren","Stehen lassen"],"correct":0,"explanation":"Der Teig muss gut durchgerührt werden."},{"sentence":"Geben Sie die Schokoladenstückchen in den Teig.","question":"Was wird in den Teig gegeben?","options":["Nüsse","Schokoladenstückchen"],"correct":1,"explanation":"Die Schokoladenstückchen werden hinzugefügt."},{"sentence":"Verteilen Sie den Teig gleichmäßig in der Form.","question":"Wie soll der Teig in der Form sein?","options":["Ungleichmäßig","Gleichmäßig"],"correct":1,"explanation":"Der Teig muss gleichmäßig verteilt werden."},{"sentence":"Überprüfen Sie den Kuchen mit einem Zahnstocher.","question":"Womit wird der Kuchen überprüft?","options":["Gabel","Zahnstocher"],"correct":1,"explanation":"Ein Zahnstocher wird zur Überprüfung verwendet."},{"sentence":"Legen Sie den Kuchen auf ein Kuchengitter.","question":"Wohin wird der Kuchen gelegt?","options":["Auf den Tisch","Auf ein Kuchengitter"],"correct":1,"explanation":"Der Kuchen kommt auf ein Kuchengitter."},{"sentence":"Fügen Sie die Eier einzeln hinzu und rühren Sie gut um.","question":"Wie werden die Eier hinzugefügt?","options":["Alle auf einmal","Einzeln"],"correct":1,"explanation":"Die Eier werden einzeln hinzugefügt."},{"sentence":"Stellen Sie sicher, dass der Ofen vorgeheizt ist.","question":"Was muss vor dem Backen gemacht werden?","options":["Ofen vorheizen","Ofen ausschalten"],"correct":0,"explanation":"Der Ofen muss vorgeheizt werden."},{"sentence":"Sie können den Kuchen mit Früchten dekorieren.","question":"Womit kann der Kuchen dekoriert werden?","options":["Früchten","Gemüse"],"correct":0,"explanation":"Früchte können zur Dekoration verwendet werden."},{"sentence":"Überlassen Sie den Kuchen für einige Minuten im Ofen.","question":"Wie lange bleibt der Kuchen im Ofen?","options":["Einige Minuten","Stunden"],"correct":0,"explanation":"Der Kuchen bleibt für einige Minuten im Ofen."},{"sentence":"Zerkleinern Sie die Kekse für den Boden.","question":"Was muss für den Boden zerkleinert werden?","options":["Kekse","Schokolade"],"correct":0,"explanation":"Die Kekse werden zerkleinert."}]}', 15);
