('de', 'A2', 'writing', 'Satzbau mit Modalverben', 'Sentence Structure with Modal Verbs', 'Bringen Sie die Wörter in Ordnung.', 'Put the words in order.', '{"type":"type_word","instructions":"Tippen Sie den Satz richtig (Modalverb an Position 2).","exercises":[{"prompt":"muss / ich / heute / arbeiten (I must work today)","expected":"ich muss heute arbeiten","hint":"Infinitiv am Ende."},{"prompt":"kannst / du / mir / helfen (Can you help me)","expected":"du kannst mir helfen","hint":"Subjekt + Modalverb."},{"prompt":"wir / wollen / Pizza / essen (We want to eat pizza)","expected":"wir wollen pizza essen","hint":"Essen am Satzende."},{"prompt":"darf / er / hier / rauchen (May he smoke here)","expected":"er darf hier rauchen","hint":"Rauchen am Ende."},{"prompt":"ihr / sollt / mehr / lernen (You should learn more)","expected":"ihr sollt mehr lernen","hint":"Lernen am Ende."},{"prompt":"kann / ich / morgen / kommen (Can I come tomorrow)","expected":"ich kann morgen kommen","hint":"Subjekt + Modalverb."},{"prompt":"sollst / du / das / machen (You should do that)","expected":"du sollst das machen","hint":"Subjekt + Modalverb."},{"prompt":"möchte / er / ein Buch / lesen (He would like to read a book)","expected":"er möchte ein Buch lesen","hint":"Infinitiv am Ende."},{"prompt":"dürfen / wir / ins Kino / gehen (We are allowed to go to the cinema)","expected":"wir dürfen ins Kino gehen","hint":"Subjekt + Modalverb."},{"prompt":"willst / du / mit mir / spielen (Do you want to play with me)","expected":"du willst mit mir spielen","hint":"Subjekt + Modalverb."},{"prompt":"muss / sie / das / verstehen (She must understand that)","expected":"sie muss das verstehen","hint":"Subjekt + Modalverb."},{"prompt":"kann / er / gut / kochen (He can cook well)","expected":"er kann gut kochen","hint":"Infinitiv am Ende."},{"prompt":"sollten / wir / früher / gehen (We should go earlier)","expected":"wir sollten früher gehen","hint":"Subjekt + Modalverb."},{"prompt":"möchtest / du / ein Eis / essen (Would you like to eat an ice cream)","expected":"du möchtest ein Eis essen","hint":"Infinitiv am Ende."},{"prompt":"müssen / sie / jetzt / anfangen (They must start now)","expected":"sie müssen jetzt anfangen","hint":"Subjekt + Modalverb."},{"prompt":"will / ich / einen Film / sehen (I want to see a movie)","expected":"ich will einen Film sehen","hint":"Infinitiv am Ende."},{"prompt":"kannst / ihr / mir / helfen (Can you help me)","expected":"ihr könnt mir helfen","hint":"Subjekt + Modalverb."},{"prompt":"dürfen / wir / hier / bleiben (Are we allowed to stay here)","expected":"wir dürfen hier bleiben","hint":"Subjekt + Modalverb."},{"prompt":"soll / er / das / wissen (He should know that)","expected":"er soll das wissen","hint":"Subjekt + Modalverb."},{"prompt":"könnte / ich / das / versuchen (Could I try that)","expected":"ich könnte das versuchen","hint":"Infinitiv am Ende."}]}', 11),
('de', 'A2', 'writing', 'Vergangenheit: Perfekt bilden', 'Past: Forming Perfekt', 'Schreiben Sie das Partizip II.', 'Write the Participle II.', '{"type":"type_word","instructions":"Ergänzen Sie das Partizip II.","exercises":[{"prompt":"Ich habe gestern eine E-Mail [to write].","expected":"geschrieben","hint":"Schreiben -> geschrieben."},{"prompt":"Wir sind nach Berlin [to drive].","expected":"gefahren","hint":"Fahren -> gefahren."},{"prompt":"Hast du deine Hausaufgaben [to do]?","expected":"gemacht","hint":"Machen -> gemacht."},{"prompt":"Er hat ein Bier [to drink].","expected":"getrunken","hint":"Trinken -> getrunken."},{"prompt":"Sie ist nach Hause [to go].","expected":"gegangen","hint":"Gehen -> gegangen."},{"prompt":"Er hat das Buch [to read].","expected":"gelesen","hint":"Lesen -> gelesen."},{"prompt":"Ich habe die Tür [to close].","expected":"geschlossen","hint":"Schließen -> geschlossen."},{"prompt":"Wir sind im Urlaub [to swim].","expected":"geschwommen","hint":"Schwimmen -> geschwommen."},{"prompt":"Sie hat den Kuchen [to bake].","expected":"gebacken","hint":"Backen -> gebacken."},{"prompt":"Du hast das Auto [to wash].","expected":"gewaschen","hint":"Waschen -> gewaschen."},{"prompt":"Ich habe den Film [to see].","expected":"gesehen","hint":"Sehen -> gesehen."},{"prompt":"Er hat das Problem [to solve].","expected":"gelöst","hint":"Lösen -> gelöst."},{"prompt":"Wir haben das Zimmer [to clean].","expected":"gereinigt","hint":"Reinigen -> gereinigt."},{"prompt":"Sie haben die Feier [to plan].","expected":"geplant","hint":"Planen -> geplant."},{"prompt":"Ich habe das Geschenk [to buy].","expected":"gekauft","hint":"Kaufen -> gekauft."},{"prompt":"Er hat die Worte [to forget].","expected":"vergessen","hint":"Vergessen -> vergessen."},{"prompt":"Sie ist spät [to come].","expected":"gekommen","hint":"Kommen -> gekommen."},{"prompt":"Wir haben die Antwort [to find].","expected":"gefunden","hint":"Finden -> gefunden."},{"prompt":"Du hast die Wahrheit [to tell].","expected":"gesagt","hint":"Sagen -> gesagt."},{"prompt":"Ich habe das Bild [to paint].","expected":"gemalt","hint":"Malen -> gemalt."}]}', 12),
('de', 'A2', 'writing', 'Nebensätze mit "weil"', 'Subordinate Clauses with "weil"', 'Verbinden Sie die Sätze.', 'Connect the sentences.', '{"type":"type_word","instructions":"Vollenden Sie den Satz (Verb am Ende!).","exercises":[{"prompt":"Ich lerne, weil es Spaß [to make].","expected":"macht","hint":"macht am Ende."},{"prompt":"Er schläft, weil er müde [to be].","expected":"ist","hint":"ist am Ende."},{"prompt":"Wir bleiben hier, weil es [to rain].","expected":"regnet","hint":"regnet am Ende."},{"prompt":"Sie lacht, weil sie glücklich [to be].","expected":"ist","hint":"ist am Ende."},{"prompt":"Ich esse, weil ich Hunger [to have].","expected":"habe","hint":"habe am Ende."},{"prompt":"Sie geht nach Hause, weil sie [to feel] müde.","expected":"fühlt","hint":"fühlt am Ende."},{"prompt":"Wir essen, weil wir Hunger [to have].","expected":"haben","hint":"haben am Ende."},{"prompt":"Er lernt, weil er die Prüfung [to pass] möchte.","expected":"bestehen","hint":"bestehen am Ende."},{"prompt":"Ich kaufe ein Buch, weil ich [to want] zu lesen.","expected":"will","hint":"will am Ende."},{"prompt":"Sie hilft mir, weil ich [to need] Unterstützung.","expected":"brauche","hint":"brauche am Ende."},{"prompt":"Wir fahren, weil das Wetter [to be] schön.","expected":"schön ist","hint":"ist am Ende."},{"prompt":"Er spielt Fußball, weil er [to like] Sport.","expected":"mag","hint":"mag am Ende."},{"prompt":"Ich gehe joggen, weil ich [to want] fit zu bleiben.","expected":"will","hint":"will am Ende."},{"prompt":"Sie tanzt, weil sie [to enjoy] die Musik.","expected":"genießt","hint":"genießt am Ende."},{"prompt":"Wir feiern, weil es [to be] dein Geburtstag.","expected":"dein Geburtstag ist","hint":"ist am Ende."},{"prompt":"Er liest, weil er [to find] die Geschichte spannend.","expected":"findet","hint":"findet am Ende."},{"prompt":"Ich höre Musik, weil ich [to relax] möchte.","expected":"entspannen","hint":"entspannen am Ende."},{"prompt":"Sie schreibt, weil sie [to want] ihre Gedanken festzuhalten.","expected":"will","hint":"will am Ende."},{"prompt":"Wir besuchen die Ausstellung, weil wir [to be] interessiert.","expected":"sind","hint":"sind am Ende."},{"prompt":"Er bleibt zu Hause, weil er [to be] krank.","expected":"krank ist","hint":"ist am Ende."}]}', 13),
('de', 'A2', 'writing', 'Präpositionen: Dativ oder Akkusativ', 'Prepositions: Dative or Accusative', 'Wählen Sie den Fall.', 'Choose the case.', '{"type":"type_word","instructions":"Tippen Sie den Artikel (dem/den/der).","exercises":[{"prompt":"Das Buch liegt auf [the] Tisch (maskulin, Ruhe).","expected":"dem","hint":"Dativ."},{"prompt":"Ich lege das Buch auf [the] Tisch (maskulin, Bewegung).","expected":"den","hint":"Akkusativ."},{"prompt":"Wir sitzen in [the] Garten (maskulin).","expected":"dem","hint":"Dativ."},{"prompt":"Sie geht in [the] Stadt (feminin).","expected":"die","hint":"Akkusativ."},{"prompt":"Der Schlüssel steckt in [the] Tür (feminin).","expected":"der","hint":"Dativ."},{"prompt":"Ich gebe das Buch an [the] Lehrer (maskulin).","expected":"dem","hint":"Dativ."},{"prompt":"Wir sehen [the] Film (maskulin).","expected":"den","hint":"Akkusativ."},{"prompt":"Die Katze schläft auf [the] Sofa (neutrum).","expected":"dem","hint":"Dativ."},{"prompt":"Ich kaufe [the] Apfel (maskulin).","expected":"den","hint":"Akkusativ."},{"prompt":"Er sitzt auf [the] Stuhl (maskulin).","expected":"dem","hint":"Dativ."},{"prompt":"Sie bringt [the] Blumen (plural).","expected":"die","hint":"Akkusativ."},{"prompt":"Wir wohnen in [the] Stadt (feminin).","expected":"der","hint":"Dativ."},{"prompt":"Ich sehe [the] Hund (maskulin).","expected":"den","hint":"Akkusativ."},{"prompt":"Das Bild hängt an [the] Wand (feminin).","expected":"der","hint":"Dativ."},{"prompt":"Sie sind in [the] Schule (feminin).","expected":"der","hint":"Dativ."},{"prompt":"Er hat [the] Idee (feminin).","expected":"die","hint":"Akkusativ."},{"prompt":"Ich stelle das Glas auf [the] Tisch (maskulin).","expected":"den","hint":"Akkusativ."},{"prompt":"Wir gehen zu [the] Park (maskulin).","expected":"dem","hint":"Dativ."},{"prompt":"Die Kinder spielen in [the] Garten (maskulin).","expected":"dem","hint":"Dativ."},{"prompt":"Ich finde [the] Schlüssel (maskulin).","expected":"den","hint":"Akkusativ."}]}', 14),
('de', 'A2', 'writing', 'Komparativ und Superlativ', 'Comparative and Superlative', 'Steigern Sie die Adjektive.', 'Increate the adjectives.', '{"type":"type_word","instructions":"Tippen Sie die Steigerungsform.","exercises":[{"prompt":"schnell -> schneller -> am ...","expected":"schnellsten","hint":"Superlativ."},{"prompt":"gut -> ... -> am besten","expected":"besser","hint":"Komparativ."},{"prompt":"hoch -> höher -> am ...","expected":"höchsten","hint":"Superlativ mit ch-Wechsel."},{"prompt":"groß -> ... -> am größten","expected":"groesser","hint":"Komparativ mit Umlaut."},{"prompt":"viel -> mehr -> am ...","expected":"meisten","hint":"Superlativ."},{"prompt":"klein -> kleiner -> am ...","expected":"kleinsten","hint":"Superlativ."},{"prompt":"schön -> schöner -> am ...","expected":"schönsten","hint":"Superlativ."},{"prompt":"teuer -> teurer -> am ...","expected":"teuersten","hint":"Superlativ."},{"prompt":"warm -> wärmer -> am ...","expected":"wärmsten","hint":"Superlativ."},{"prompt":"lang -> länger -> am ...","expected":"längsten","hint":"Superlativ."},{"prompt":"dumm -> dümmer -> am ...","expected":"dümmsten","hint":"Superlativ."},{"prompt":"stark -> stärker -> am ...","expected":"stärksten","hint":"Superlativ."},{"prompt":"freundlich -> freundlicher -> am ...","expected":"freundlichsten","hint":"Superlativ."},{"prompt":"neu -> neuer -> am ...","expected":"neuesten","hint":"Superlativ."},{"prompt":"süß -> süßer -> am ...","expected":"süßesten","hint":"Superlativ."},{"prompt":"schwer -> schwerer -> am ...","expected":"schwersten","hint":"Superlativ."},{"prompt":"hell -> heller -> am ...","expected":"hellsten","hint":"Superlativ."},{"prompt":"kurz -> kürzer -> am ...","expected":"kürzesten","hint":"Superlativ."},{"prompt":"klug -> klüger -> am ...","expected":"klügsten","hint":"Superlativ mit u-Wechsel."},{"prompt":"hart -> härter -> am ...","expected":"härtesten","hint":"Superlativ mit ä-Wechsel."}]}', 15);
